"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[5285],{1037(t,e,i){i.r(e),i.d(e,{comp:()=>a,data:()=>s});var n=i(641);const o={},a=(0,i(6262).A)(o,[["render",function(t,e){return(0,n.uX)(),(0,n.CE)("div",null,[...e[0]||(e[0]=[(0,n.Fv)('<h1 id="customer-notifications" tabindex="-1"><a class="header-anchor" href="#customer-notifications"><span>Customer Notifications</span></a></h1><p>What customers receive, when, and how to manage their preferences.</p><h2 id="channels" tabindex="-1"><a class="header-anchor" href="#channels"><span>Channels</span></a></h2><table><thead><tr><th>Channel</th><th>Always on?</th><th>Configured by</th></tr></thead><tbody><tr><td><strong>Email</strong></td><td>Yes (defaults)</td><td>Customer can disable per-trigger</td></tr><tr><td><strong>In-app toast / badge</strong></td><td>Yes (when on the site)</td><td>Always on</td></tr><tr><td><strong>Push</strong></td><td>Optional</td><td>Customer enables <a href="/firebase.html" target="_blank" rel="noopener noreferrer">Firebase</a> push</td></tr><tr><td><strong>SMS</strong></td><td>Optional</td><td>Customer adds phone via <a href="/twilio.html" target="_blank" rel="noopener noreferrer">Twilio</a></td></tr></tbody></table><h2 id="notification-preferences-page" tabindex="-1"><a class="header-anchor" href="#notification-preferences-page"><span>Notification preferences page</span></a></h2><p><strong>My Account → Notification Preferences</strong> — customers tick / untick each notification.</p><table><thead><tr><th>Trigger</th><th>Email</th><th>Push</th><th>SMS</th></tr></thead><tbody><tr><td>Bid placed (your bid)</td><td>yes</td><td>yes</td><td>no</td></tr><tr><td>Outbid</td><td>yes</td><td>yes</td><td>optional</td></tr><tr><td>Auction starting soon (watching)</td><td>yes</td><td>yes</td><td>no</td></tr><tr><td>Auction ending soon (active bid)</td><td>yes</td><td>yes</td><td>yes</td></tr><tr><td>Auction won</td><td>yes</td><td>yes</td><td>yes</td></tr><tr><td>Auction lost</td><td>optional</td><td>no</td><td>no</td></tr><tr><td>Payment reminder</td><td>yes</td><td>no</td><td>yes</td></tr><tr><td>Payment confirmation</td><td>yes</td><td>no</td><td>no</td></tr><tr><td>Watchlist activity</td><td>yes</td><td>optional</td><td>no</td></tr><tr><td>Wallet credited</td><td>yes</td><td>no</td><td>no</td></tr><tr><td>Wallet debited (auction win)</td><td>yes</td><td>no</td><td>no</td></tr><tr><td>Withdrawal status</td><td>yes</td><td>no</td><td>optional</td></tr><tr><td>Direct message received</td><td>yes</td><td>yes</td><td>no</td></tr><tr><td>New auction from followed seller</td><td>yes</td><td>optional</td><td>no</td></tr></tbody></table><p>Default mix is friendly — mostly email with select push / SMS for time-sensitive events.</p><h2 id="email-notifications" tabindex="-1"><a class="header-anchor" href="#email-notifications"><span>Email notifications</span></a></h2><h3 id="bid-placed-you-bid" tabindex="-1"><a class="header-anchor" href="#bid-placed-you-bid"><span>Bid placed (you bid)</span></a></h3><blockquote><p><strong>Subject:</strong> &quot;Bid placed — {auction title}&quot; <strong>When:</strong> Every time you successfully place a bid <strong>Body:</strong> confirms amount + auction details + link</p></blockquote><h3 id="outbid" tabindex="-1"><a class="header-anchor" href="#outbid"><span>Outbid</span></a></h3><blockquote><p><strong>Subject:</strong> &quot;You&#39;ve been outbid on {auction title}&quot; <strong>When:</strong> Another bidder beats your bid <strong>Body:</strong> new high amount + one-click rebid button + link</p></blockquote><h3 id="auction-won" tabindex="-1"><a class="header-anchor" href="#auction-won"><span>Auction won</span></a></h3><blockquote><p><strong>Subject:</strong> &quot;🎉 You won {auction title}!&quot; <strong>When:</strong> Auction closes with you as winner <strong>Body:</strong> winning amount + payment instructions + link to checkout</p></blockquote><h3 id="auction-lost" tabindex="-1"><a class="header-anchor" href="#auction-lost"><span>Auction lost</span></a></h3><blockquote><p><strong>Subject:</strong> &quot;Auction ended — {auction title}&quot; <strong>When:</strong> Auction closes and you&#39;re not the winner <strong>Body:</strong> winning amount + similar lots + watchlist suggestion</p></blockquote><h3 id="payment-reminder" tabindex="-1"><a class="header-anchor" href="#payment-reminder"><span>Payment reminder</span></a></h3><blockquote><p><strong>Subject:</strong> &quot;Action needed: pay for {auction title}&quot; <strong>When:</strong> N hours after win (if unpaid; default 24) <strong>Body:</strong> payment link + deadline + consequences (relist if not paid)</p></blockquote><h3 id="watchlist-activity" tabindex="-1"><a class="header-anchor" href="#watchlist-activity"><span>Watchlist activity</span></a></h3><blockquote><p><strong>Subject:</strong> &quot;Activity on a lot you&#39;re watching&quot; <strong>When:</strong> Configurable triggers — auction starting, first bid, ending soon <strong>Body:</strong> auction state + link</p></blockquote><p><a href="/notifications.html" target="_blank" rel="noopener noreferrer">Full notification reference →</a></p><h2 id="in-app-notifications" tabindex="-1"><a class="header-anchor" href="#in-app-notifications"><span>In-app notifications</span></a></h2><p>While the customer is browsing the site, in-app notifications appear as:</p><table><thead><tr><th>Format</th><th>When</th></tr></thead><tbody><tr><td><strong>Toast (auto-dismiss)</strong></td><td>Outbid, ending soon, watchlist activity</td></tr><tr><td><strong>Persistent badge</strong></td><td>Unread message count, won-auctions awaiting payment</td></tr><tr><td><strong>Modal</strong></td><td>Auction won, urgent action needed</td></tr></tbody></table><p>Toasts dismiss automatically after 5 seconds; can be clicked to open the source.</p><p>The bell icon in the site header shows the unread count. Clicking opens the notification drawer.</p><h2 id="push-notifications" tabindex="-1"><a class="header-anchor" href="#push-notifications"><span>Push notifications</span></a></h2><p>If <a href="/firebase.html" target="_blank" rel="noopener noreferrer">Firebase</a> is configured and the user has granted push permission:</p><table><thead><tr><th>Trigger</th><th>Push?</th></tr></thead><tbody><tr><td>Outbid</td><td>yes (instant)</td></tr><tr><td>Auction ending soon (5 min)</td><td>yes</td></tr><tr><td>Auction won</td><td>yes</td></tr><tr><td>Direct message</td><td>yes</td></tr></tbody></table><p>User opts in via:</p><ol><li>Visit the site</li><li>Browser shows &quot;Enable notifications?&quot;</li><li>Click <strong>Allow</strong></li><li>Token saved; pushes route via Firebase</li></ol><p><a href="/firebase.html" target="_blank" rel="noopener noreferrer">Firebase setup →</a></p><h2 id="sms-notifications" tabindex="-1"><a class="header-anchor" href="#sms-notifications"><span>SMS notifications</span></a></h2><p>If <a href="/twilio.html" target="_blank" rel="noopener noreferrer">Twilio</a> is configured and the user has added a phone number:</p><table><thead><tr><th>Trigger</th><th>SMS?</th></tr></thead><tbody><tr><td>Outbid (final hour)</td><td>yes</td></tr><tr><td>Auction won</td><td>yes</td></tr><tr><td>Payment reminder</td><td>yes</td></tr><tr><td>Withdrawal paid</td><td>optional</td></tr><tr><td>OTP for wallet transfer</td><td>yes (always)</td></tr></tbody></table><p>User adds phone via:</p><p><strong>My Account → Account details → Phone number</strong>.</p><p>Phone must be E.164 format (e.g. <code>+15551234567</code>). The plugin sends an OTP to verify ownership before saving.</p><h2 id="unsubscribe-links" tabindex="-1"><a class="header-anchor" href="#unsubscribe-links"><span>Unsubscribe links</span></a></h2><p>Every email includes an <strong>Unsubscribe</strong> link for that specific notification type. Clicking:</p><ol><li>Toggles that notification off in the user&#39;s preferences</li><li>Confirms with a one-click landing page</li><li>They can re-enable in <strong>Notification Preferences</strong> later</li></ol><p>Bulk-unsubscribe (all auction emails) is available via a single link.</p><h2 id="snooze" tabindex="-1"><a class="header-anchor" href="#snooze"><span>Snooze</span></a></h2><p>Customers can <strong>Snooze all notifications</strong> for a period (1 hour / 1 day / 1 week / until I un-snooze). Useful for vacations.</p><p>Snoozed notifications are queued and delivered after the snooze ends — except time-sensitive ones (outbid, won) which are still delivered immediately.</p><h2 id="email-digest" tabindex="-1"><a class="header-anchor" href="#email-digest"><span>Email digest</span></a></h2><p>For low-priority notifications, customers can opt into a <strong>daily digest</strong> instead of individual emails:</p><table><thead><tr><th>Setting</th><th>Effect</th></tr></thead><tbody><tr><td>Digest enabled</td><td>Bundles non-urgent notifications</td></tr><tr><td>Digest send time</td><td>Customer&#39;s preferred hour (UTC)</td></tr><tr><td>Digest frequency</td><td>Daily / Weekly</td></tr></tbody></table><p>Time-sensitive notifications (outbid, won, ending soon) are always sent individually regardless of digest setting.</p><h2 id="privacy" tabindex="-1"><a class="header-anchor" href="#privacy"><span>Privacy</span></a></h2><ul><li>Email is required for any notifications</li><li>Phone is opt-in only</li><li>Push token is browser-stored; expires per Firebase</li><li>Unsubscribe history is logged for compliance (GDPR)</li></ul><p>GDPR exporter includes notification preferences.</p>',53)])])}]]),s=JSON.parse('{"path":"/customer-notifications.html","title":"Customer Notifications","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"Channels","slug":"channels","link":"#channels","children":[]},{"level":2,"title":"Notification preferences page","slug":"notification-preferences-page","link":"#notification-preferences-page","children":[]},{"level":2,"title":"Email notifications","slug":"email-notifications","link":"#email-notifications","children":[{"level":3,"title":"Bid placed (you bid)","slug":"bid-placed-you-bid","link":"#bid-placed-you-bid","children":[]},{"level":3,"title":"Outbid","slug":"outbid","link":"#outbid","children":[]},{"level":3,"title":"Auction won","slug":"auction-won","link":"#auction-won","children":[]},{"level":3,"title":"Auction lost","slug":"auction-lost","link":"#auction-lost","children":[]},{"level":3,"title":"Payment reminder","slug":"payment-reminder","link":"#payment-reminder","children":[]},{"level":3,"title":"Watchlist activity","slug":"watchlist-activity","link":"#watchlist-activity","children":[]}]},{"level":2,"title":"In-app notifications","slug":"in-app-notifications","link":"#in-app-notifications","children":[]},{"level":2,"title":"Push notifications","slug":"push-notifications","link":"#push-notifications","children":[]},{"level":2,"title":"SMS notifications","slug":"sms-notifications","link":"#sms-notifications","children":[]},{"level":2,"title":"Unsubscribe links","slug":"unsubscribe-links","link":"#unsubscribe-links","children":[]},{"level":2,"title":"Snooze","slug":"snooze","link":"#snooze","children":[]},{"level":2,"title":"Email digest","slug":"email-digest","link":"#email-digest","children":[]},{"level":2,"title":"Privacy","slug":"privacy","link":"#privacy","children":[]}],"git":{},"filePathRelative":"customer-notifications.md"}')}}]);